1728	int8_t* nn_mat_mult_kernel_s8_offset_v2(const int8_t *input_a,
1729	            const int8_t *input_b,
1730	            const int32_t out_tensor_ch,
1731	            const int32_t *out_shift,
1732	            const int32_t *out_scale,
1733	            const int32_t in_offset,    //value is in the range of [-127, 128]
1734	            const int32_t out_offset,   //value is in the range of [-128, 127]
1735	            const int32_t act_min,
1736	            const int32_t act_max,
1737	            const int32_t num_col_a,
1738	            const int32_t *contri_buf,
1739	            int8_t *out)
1740	{
1741	#if defined(ENA_VEC_ISA) && (NDS_VEC_RVV_VERSION >= 100) && defined(ENA_NDS_V5_VEC_DOT_PROD)    // unpack the 4-bit weight into a temporary buffer
1742	    (void)in_offset;
1743	
1744	    /* set up the second output pointers */
1745	    int8_t *out_0 = out;
1746	    int8_t *out_1 = out_0 + out_tensor_ch;
1747	    const int8_t *ptr_a0 = input_a;
1748	    long vl;
1749	
1750	    long maxvl_per_loop;
1751	    NDS_VEC_VSETVLI(maxvl_per_loop, reg_x0, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M4);
1752	
1753	    for (long cur_row = 0; (cur_row + 2) <= out_tensor_ch; cur_row += 2)
1754	    {
1755	        /* setup pointers for B */
1756	        const int8_t *ptr_b0 = input_b;
1757	        const int8_t *ptr_b1 = ptr_b0 + num_col_a;
1758	
1759	        /* align the second pointer for A */
1760	        const int8_t *ptr_a1 = ptr_a0 + num_col_a;
1761	
1762	        //init the accumulator
1763	        NDS_VEC_VSETVLI(vl, num_col_a, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M4);
1764	        NDS_VEC_VAND_VI(NDS_VEC_V0, NDS_VEC_V0, 0x0);
1765	        NDS_VEC_VAND_VI(NDS_VEC_V4, NDS_VEC_V4, 0x0);
1766	        NDS_VEC_VAND_VI(NDS_VEC_V8, NDS_VEC_V8, 0x0);
1767	        NDS_VEC_VAND_VI(NDS_VEC_V12, NDS_VEC_V12, 0x0);
1768	
1769	        long col_count = num_col_a;
1770	        while(col_count >= maxvl_per_loop)
1771	        {
1772	            NDS_VEC_VSETVLI(vl, col_count, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M4);
1773	            NDS_VEC_VLE8_V(NDS_VEC_V16, ptr_a0);
1774	            NDS_VEC_VLE8_V(NDS_VEC_V24, ptr_b0);
1775	            NDS_VEC_VLE8_V(NDS_VEC_V28, ptr_b1);
1776	            NDS_VEC_VLE8_V(NDS_VEC_V20, ptr_a1);
1777	            ptr_a0 += vl;
1778	            ptr_a1 += vl;
1779	            ptr_b0 += vl;
1780	            ptr_b1 += vl;
1781	            col_count -= vl;
1782	
1783	            NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M4);
1784	            NDS_VEC_VD4DOTS_VV(NDS_VEC_V0, NDS_VEC_V16, NDS_VEC_V24);   //ch_0_out_0 += a0 * b0;
1785	            NDS_VEC_VD4DOTS_VV(NDS_VEC_V4, NDS_VEC_V16, NDS_VEC_V28);   //ch_0_out_1 += a0 * b1;
1786	            NDS_VEC_VD4DOTS_VV(NDS_VEC_V8, NDS_VEC_V20, NDS_VEC_V24);   //ch_1_out_0 += a1 * b0;
1787	            NDS_VEC_VD4DOTS_VV(NDS_VEC_V12, NDS_VEC_V20, NDS_VEC_V28);  //ch_1_out_1 += a1 * b1;
1788	        }
1789	
1790	        //extra process for the case of elements to be dot producted is not a mutiple of 4
1791	        if(col_count > 0)
1792	        {
1793	            //clean one of the dot product source
1794	            long tmp_avl;
1795	            tmp_avl = col_count + 3;
1796	            NDS_VEC_VSETVLI(vl, tmp_avl, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M4);
1797	            NDS_VEC_VAND_VI(NDS_VEC_V24, NDS_VEC_V24, 0);
1798	            NDS_VEC_VAND_VI(NDS_VEC_V28, NDS_VEC_V28, 0);
1799	
1800	            NDS_VEC_VSETVLI(vl, col_count, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M4);
1801	            NDS_VEC_VLE8_V(NDS_VEC_V16, ptr_a0);
1802	            NDS_VEC_VLE8_V(NDS_VEC_V24, ptr_b0);
1803	            NDS_VEC_VLE8_V(NDS_VEC_V28, ptr_b1);
1804	            NDS_VEC_VLE8_V(NDS_VEC_V20, ptr_a1);
1805	            ptr_a0 += vl;
1806	            ptr_a1 += vl;
1807	            ptr_b0 += vl;
1808	            ptr_b1 += vl;
1809	            col_count -= vl;
1810	
1811	            vl = (vl + 3) >> 2;
1812	            NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M4);
1813	            NDS_VEC_VD4DOTS_VV(NDS_VEC_V0, NDS_VEC_V16, NDS_VEC_V24);   //ch_0_out_0 += a0 * b0;
1814	            NDS_VEC_VD4DOTS_VV(NDS_VEC_V4, NDS_VEC_V16, NDS_VEC_V28);   //ch_0_out_1 += a0 * b1;
1815	            NDS_VEC_VD4DOTS_VV(NDS_VEC_V8, NDS_VEC_V20, NDS_VEC_V24);   //ch_1_out_0 += a1 * b0;
1816	            NDS_VEC_VD4DOTS_VV(NDS_VEC_V12, NDS_VEC_V20, NDS_VEC_V28);  //ch_1_out_1 += a1 * b1;
1817	        }
1818	
1819	        NDS_VEC_VSETVLI(vl, 1, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);
1820	        NDS_VEC_VAND_VI(NDS_VEC_V31, NDS_VEC_V31, 0);
1821	        NDS_VEC_VSETVLI(vl, num_col_a, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M4);   //note the avl here
1822	        NDS_VEC_VREDSUM_VS(NDS_VEC_V0, NDS_VEC_V0, NDS_VEC_V31);    //ch_0_out_0
1823	        NDS_VEC_VREDSUM_VS(NDS_VEC_V1, NDS_VEC_V4, NDS_VEC_V31);    //ch_0_out_1
1824	        NDS_VEC_VREDSUM_VS(NDS_VEC_V2, NDS_VEC_V8, NDS_VEC_V31);    //ch_1_out_0
1825	        NDS_VEC_VREDSUM_VS(NDS_VEC_V3, NDS_VEC_V12, NDS_VEC_V31);   //ch_1_out_1
1826	
1827	        NDS_VEC_VSETVLI(vl, 2, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);
1828	        NDS_VEC_VSLIDEUP_VI(NDS_VEC_V0, NDS_VEC_V2, 1);
1829	        NDS_VEC_VSLIDEUP_VI(NDS_VEC_V1, NDS_VEC_V3, 1);
1830	
1831	        //add extra contribution back
1832	        NDS_VEC_VLE32_V(NDS_VEC_V4, contri_buf);
1833	        contri_buf += vl;
1834	        NDS_VEC_VADD_VV(NDS_VEC_V0, NDS_VEC_V0, NDS_VEC_V4);
1835	        NDS_VEC_VADD_VV(NDS_VEC_V1, NDS_VEC_V1, NDS_VEC_V4);
1836	
1837	        //===== Quantize down =====
1838	        NDS_VEC_VLE32_V(NDS_VEC_V2, out_shift);
1839	        NDS_VEC_VLE32_V(NDS_VEC_V3, out_scale);
1840	        NDS_VEC_VRSUB_VX(NDS_VEC_V2, NDS_VEC_V2, 30);
1841	
1842	        NDS_VEC_VWMUL_VV(NDS_VEC_V4, NDS_VEC_V0, NDS_VEC_V3);
1843	        NDS_VEC_VWMUL_VV(NDS_VEC_V6, NDS_VEC_V1, NDS_VEC_V3);
1844	        NDS_VEC_VNSRA_WV(NDS_VEC_V4, NDS_VEC_V4, NDS_VEC_V2);
1845	        NDS_VEC_VNSRA_WV(NDS_VEC_V6, NDS_VEC_V6, NDS_VEC_V2);
1846	        NDS_VEC_VSSRA_VI(NDS_VEC_V4, NDS_VEC_V4, 1);
1847	        NDS_VEC_VSSRA_VI(NDS_VEC_V6, NDS_VEC_V6, 1);
1848	
1849	        // Add offset
1850	        NDS_VEC_VADD_VX(NDS_VEC_V4, NDS_VEC_V4, out_offset);
1851	        NDS_VEC_VADD_VX(NDS_VEC_V6, NDS_VEC_V6, out_offset);
1852	
1853	        // Clamp the result
1854	        NDS_VEC_VMAX_VX(NDS_VEC_V4, NDS_VEC_V4, act_min);
1855	        NDS_VEC_VMIN_VX(NDS_VEC_V4, NDS_VEC_V4, act_max);
1856	        NDS_VEC_VMAX_VX(NDS_VEC_V6, NDS_VEC_V6, act_min);
1857	        NDS_VEC_VMIN_VX(NDS_VEC_V6, NDS_VEC_V6, act_max);
1858	
1859	        //narrowing and store the results
1860	        NDS_VEC_VSETVLI(vl, 2, NDS_VEC_VTYPE_SEW_E16, NDS_VEC_VTYPE_LMUL_M1);
1861	        NDS_VEC_VNSRA_VI(NDS_VEC_V4, NDS_VEC_V4, 0);
1862	        NDS_VEC_VNSRA_VI(NDS_VEC_V6, NDS_VEC_V6, 0);
1863	        NDS_VEC_VSETVLI(vl, 2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M1);
1864	        NDS_VEC_VNSRA_VI(NDS_VEC_V4, NDS_VEC_V4, 0);
1865	        NDS_VEC_VNSRA_VI(NDS_VEC_V6, NDS_VEC_V6, 0);
1866	        NDS_VEC_VSE8_V(NDS_VEC_V4, out_0);
1867	        NDS_VEC_VSE8_V(NDS_VEC_V6, out_1);
1868	        out_0 += vl;
1869	        out_1 += vl;
1870	        out_scale += vl;
1871	        out_shift += vl;
1872	
1873	        ptr_a0 += num_col_a;
1874	    }
1875	
1876	    /* compute the last odd numbered row if any */
1877	    if (out_tensor_ch & 0x1)
1878	    {
1879	        /* setup pointers for B */
1880	        const int8_t *ptr_b0 = input_b;
1881	        const int8_t *ptr_b1 = ptr_b0 + num_col_a;
1882	
1883	        const long load_stride_byte = 0;
1884	        const long store_stride_byte = sizeof(*out) * out_tensor_ch;
1885	
1886	        //init the accumulator
1887	        NDS_VEC_VSETVLI(vl, num_col_a, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M4);
1888	        NDS_VEC_VAND_VI(NDS_VEC_V0, NDS_VEC_V0, 0x0);
1889	        NDS_VEC_VAND_VI(NDS_VEC_V4, NDS_VEC_V4, 0x0);
1890	
1891	        long col_count = num_col_a;
1892	        while(col_count >= maxvl_per_loop)
1893	        {
1894	            NDS_VEC_VSETVLI(vl, col_count, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M4);
1895	            NDS_VEC_VLE8_V(NDS_VEC_V16, ptr_a0);
1896	            NDS_VEC_VLE8_V(NDS_VEC_V24, ptr_b0);
1897	            NDS_VEC_VLE8_V(NDS_VEC_V28, ptr_b1);
1898	            ptr_a0 += vl;
1899	            ptr_b0 += vl;
1900	            ptr_b1 += vl;
1901	            col_count -= vl;
1902	
1903	            NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M4);
1904	            NDS_VEC_VD4DOTS_VV(NDS_VEC_V0, NDS_VEC_V16, NDS_VEC_V24);   //ch_0_out_0 += a0 * b0;
1905	            NDS_VEC_VD4DOTS_VV(NDS_VEC_V4, NDS_VEC_V16, NDS_VEC_V28);   //ch_0_out_1 += a0 * b1;
1906	        }
1907	
1908	        //extra process for the case of elements to be dot producted is not a mutiple of 4
1909	        if(col_count > 0)
1910	        {
1911	            //clean one of the dot product source
1912	            long tmp_avl;
1913	            tmp_avl = col_count + 3;
1914	            NDS_VEC_VSETVLI(vl, tmp_avl, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M4);
1915	            NDS_VEC_VAND_VI(NDS_VEC_V16, NDS_VEC_V16, 0);
1916	
1917	            NDS_VEC_VSETVLI(vl, col_count, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M4);
1918	            NDS_VEC_VLE8_V(NDS_VEC_V16, ptr_a0);
1919	            NDS_VEC_VLE8_V(NDS_VEC_V24, ptr_b0);
1920	            NDS_VEC_VLE8_V(NDS_VEC_V28, ptr_b1);
1921	            ptr_a0 += vl;
1922	            ptr_b0 += vl;
1923	            ptr_b1 += vl;
1924	            col_count -= vl;
1925	
1926	            vl = (vl + 3) >> 2;
1927	            NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M4);
1928	            NDS_VEC_VD4DOTS_VV(NDS_VEC_V0, NDS_VEC_V16, NDS_VEC_V24);   //ch_0_out_0 += a0 * b0;
1929	            NDS_VEC_VD4DOTS_VV(NDS_VEC_V4, NDS_VEC_V16, NDS_VEC_V28);   //ch_0_out_1 += a0 * b1;
1930	        }
1931	
1932	        NDS_VEC_VSETVLI(vl, 1, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);
1933	        NDS_VEC_VAND_VI(NDS_VEC_V31, NDS_VEC_V31, 0);
1934	        NDS_VEC_VSETVLI(vl, num_col_a, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M4);   //note the avl here
1935	        NDS_VEC_VREDSUM_VS(NDS_VEC_V0, NDS_VEC_V0, NDS_VEC_V31);    //ch_0_out_0
1936	        NDS_VEC_VREDSUM_VS(NDS_VEC_V1, NDS_VEC_V4, NDS_VEC_V31);    //ch_0_out_1
1937	
1938	        NDS_VEC_VSETVLI(vl, 2, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);
1939	        NDS_VEC_VSLIDEUP_VI(NDS_VEC_V0, NDS_VEC_V1, 1);
1940	
1941	        //add extra contribution back
1942	        NDS_VEC_VLSE32_V(NDS_VEC_V4, contri_buf, load_stride_byte);
1943	        contri_buf++;
1944	        NDS_VEC_VADD_VV(NDS_VEC_V0, NDS_VEC_V0, NDS_VEC_V4);
1945	
1946	        //===== Quantize down =====
1947	        NDS_VEC_VLSE32_V(NDS_VEC_V2, out_shift, load_stride_byte);
1948	        NDS_VEC_VLSE32_V(NDS_VEC_V3, out_scale, load_stride_byte);
1949	        NDS_VEC_VRSUB_VX(NDS_VEC_V2, NDS_VEC_V2, 30);
1950	
1951	        NDS_VEC_VWMUL_VV(NDS_VEC_V4, NDS_VEC_V0, NDS_VEC_V3);
1952	        NDS_VEC_VNSRA_WV(NDS_VEC_V4, NDS_VEC_V4, NDS_VEC_V2);
1953	        NDS_VEC_VSSRA_VI(NDS_VEC_V4, NDS_VEC_V4, 1);
1954	
1955	        // Add offset
1956	        NDS_VEC_VADD_VX(NDS_VEC_V4, NDS_VEC_V4, out_offset);
1957	
1958	        // Clamp the result
1959	        NDS_VEC_VMAX_VX(NDS_VEC_V4, NDS_VEC_V4, act_min);
1960	        NDS_VEC_VMIN_VX(NDS_VEC_V4, NDS_VEC_V4, act_max);
1961	
1962	        //narrowing and store the results
1963	        NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E16, NDS_VEC_VTYPE_LMUL_M1);
1964	        NDS_VEC_VNSRA_VI(NDS_VEC_V4, NDS_VEC_V4, 0);
1965	        NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M1);
1966	        NDS_VEC_VNSRA_VI(NDS_VEC_V4, NDS_VEC_V4, 0);
1967	        NDS_VEC_VSSE8_V(NDS_VEC_V4, out_0, store_stride_byte);
1968	        out_0++;
1969	        out_scale++;
1970	        out_shift++;
1971	    }
1972	
1973	    out_0 += out_tensor_ch;
1974	
1975	    /* return the new output pointer with offset */
1976	    return out_0;
1977	#elif defined(ENA_DSP_ISA_64)
1978	    (void)in_offset;
1979	
1980	    /* set up the second output pointers */
1981	    int8_t *out_0 = out;
1982	    int8_t *out_1 = out_0 + out_tensor_ch;
1983	    const int8_t *ptr_a0 = input_a;
1984	
1985	    for (long cur_row = 0; (cur_row + 2) <= out_tensor_ch; cur_row += 2)
1986	    {
1987	        /* setup pointers for B */
1988	        const int8_t *ptr_b0 = input_b;
1989	        const int8_t *ptr_b1 = ptr_b0 + num_col_a;
1990	
1991	        /* align the second pointer for A */
1992	        const int8_t *ptr_a1 = ptr_a0 + num_col_a;
1993	
1994	        // init the accumulators
1995	        long ch_0_out_0 = 0;
1996	        long ch_0_out_1 = 0;
1997	        long ch_1_out_0 = 0;
1998	        long ch_1_out_1 = 0;
1999	
2000	        long col_count = num_col_a;
2001	        while (col_count >= SIMD_NUM_Q7)
2002	        {
2003	            suni_t a0 = simd_load_8((s8_t*)ptr_a0, 0);
2004	            suni_t a1 = simd_load_8((s8_t*)ptr_a1, 0);
2005	            suni_t b0 = simd_load_8((s8_t*)ptr_b0, 0);
2006	            suni_t b1 = simd_load_8((s8_t*)ptr_b1, 0);
2007	
2008	            ch_0_out_0 = NDS_DSP_SMAQA(ch_0_out_0, a0.l0, b0.l0);
2009	            ch_0_out_1 = NDS_DSP_SMAQA(ch_0_out_1, a0.l0, b1.l0);
2010	            ch_1_out_0 = NDS_DSP_SMAQA(ch_1_out_0, a1.l0, b0.l0);
2011	            ch_1_out_1 = NDS_DSP_SMAQA(ch_1_out_1, a1.l0, b1.l0);
2012	
2013	            ptr_a0 += SIMD_NUM_Q7;
2014	            ptr_a1 += SIMD_NUM_Q7;
2015	            ptr_b0 += SIMD_NUM_Q7;
2016	            ptr_b1 += SIMD_NUM_Q7;
2017	            col_count -= SIMD_NUM_Q7;
2018	        }
2019	
2020	        // sum up the high and low part result
2021	        ch_0_out_0 = PADD_S32(ch_0_out_0);
2022	        ch_0_out_1 = PADD_S32(ch_0_out_1);
2023	        ch_1_out_0 = PADD_S32(ch_1_out_0);
2024	        ch_1_out_1 = PADD_S32(ch_1_out_1);
2025	
2026	        // rest loop
2027	        int32_t ch_0_out_0_s32 = 0;
2028	        int32_t ch_0_out_1_s32 = 0;
2029	        int32_t ch_1_out_0_s32 = 0;
2030	        int32_t ch_1_out_1_s32 = 0;
2031	        while (col_count > 0)
2032	        {
2033	            int8_t a0 = *ptr_a0++;
2034	            int8_t b0 = *ptr_b0++;
2035	            int8_t a1 = *ptr_a1++;
2036	            int8_t b1 = *ptr_b1++;
2037	
2038	            ch_0_out_0_s32 += a0 * b0;
2039	            ch_0_out_1_s32 += a0 * b1;
2040	            ch_1_out_0_s32 += a1 * b0;
2041	            ch_1_out_1_s32 += a1 * b1;
2042	            col_count--;
2043	        }
2044	        ch_0_out_0 += ch_0_out_0_s32;
2045	        ch_0_out_1 += ch_0_out_1_s32;
2046	        ch_1_out_0 += ch_1_out_0_s32;
2047	        ch_1_out_1 += ch_1_out_1_s32;
2048	
2049	        //add extra contribution back
2050	        ch_0_out_0 += contri_buf[cur_row];
2051	        ch_0_out_1 += contri_buf[cur_row];
2052	        ch_1_out_0 += contri_buf[cur_row + 1];
2053	        ch_1_out_1 += contri_buf[cur_row + 1];
2054	
2055	        ch_0_out_0 = nn_requantize(ch_0_out_0, *out_scale, *out_shift);
2056	        ch_0_out_0 += out_offset;
2057	        ch_0_out_0 = MAX(ch_0_out_0, act_min);
2058	        ch_0_out_0 = MIN(ch_0_out_0, act_max);
2059	        *out_0++ = (int8_t)ch_0_out_0;
2060	
2061	        ch_0_out_1 = nn_requantize(ch_0_out_1, *out_scale, *out_shift);
2062	        ch_0_out_1 += out_offset;
2063	        ch_0_out_1 = MAX(ch_0_out_1, act_min);
